document.addEventListener('DOMContentLoaded', function () {
  // Mark any section with anchor "blog-summary" as swipe-ignored
  document.querySelectorAll('[data-anchor="blog-summary"]').forEach(function (section) {
    section.setAttribute('data-swipe-ignore', 'true');
  });

  document.querySelectorAll('.summary-item-list').forEach(function (container) {
    if (container.closest('[data-swipe-ignore="true"]')) return;

    var startX = 0;
    var startY = 0;
    var isDragging = false;
    container.addEventListener('touchstart', function (e) {
      startX = e.touches[0].clientX;
      startY = e.touches[0].clientY;
      isDragging = false;
    }, { passive: true });
    container.addEventListener('touchmove', function (e) {
      isDragging = true;
    }, { passive: true });
    container.addEventListener('touchend', function (e) {
      if (!isDragging) return;
      var diffX = startX - e.changedTouches[0].clientX;
      var diffY = startY - e.changedTouches[0].clientY;
      if (Math.abs(diffX) < 40 || Math.abs(diffX) < Math.abs(diffY)) return;
      if (diffX > 0) {
        container.querySelector('.summary-carousel-pager-next').click();
      } else {
        container.querySelector('.summary-carousel-pager-prev').click();
      }
    }, { passive: true });
  });
});
